import { useMemo } from 'react'
import { useProject } from 'utils/project'
import { useSetUrlSearchParams, useUrlQueryParam } from 'utils/url'

// 项目列表搜索的参数hook
export const useProjectsSearchParams = () => {
  const [param, setParam] = useUrlQueryParam(['name', 'personId'])
  return [useMemo(() => ({...param, personId: Number(param.personId) || undefined}), [param]), setParam] as const
}

export const useProjectsQueryKey =  () =>  {
  const [params] = useProjectsSearchParams()
  return ['projects', params]
}

export const useProjectModal = () => {
  const [{projectCreate}, setProjectCreate] = useUrlQueryParam(['projectCreate'])
  const [{editingProjectId}, setEditingProjectId] = useUrlQueryParam(['editingProjectId'])
  const {data:  editingProject, isLoading} = useProject(Number(editingProjectId))
  const setSerachParams = useSetUrlSearchParams()
  const open = () => setProjectCreate({projectCreate: true})
  const close = () => {
    setSerachParams({projectCreate: undefined, editingProjectId: undefined})
  }
  

  const startEdit = (id: number) => setEditingProjectId({editingProjectId: id})

  // return [ // 元组数组返回的形式
  //   projectCreate === 'true',
  //   open,
  //   close
  // ] as const
  
  
  return {
    projectModalOpen: projectCreate === 'true' || Boolean(editingProjectId),
    editingProject,
    isLoading,
    open,
    close,
    startEdit
  }
}