import { QueryKey, useMutation, useQuery } from 'react-query'
import { Kanban } from 'types/kanban'
import { useHttp } from './http'
import { useAddConfig, useDeleteConfig, useReorderTaskConfig } from './use-optimistic-options'

export  interface SortProps {
  type: 'before'  | 'after'
  referenceId: number
  fromId: number
  fromKanbanId?: number
  toKanbanId?: number
}

export const useKanbans = (param?: Partial<Kanban>) => {
	const client = useHttp()
  return useQuery<Kanban[]>(['kanbans', param], () => client('kanbans', { data: param }))
}

export const useAddKanban = (queryKey: QueryKey) => {
	const client = useHttp()
  return useMutation((params: Partial<Kanban>) => client(`kanbans`, { data: params, method: 'POST' }), 
  useAddConfig(queryKey))
}

export const useDeleteKanban = (queryKey: QueryKey) => {
  const client = useHttp()
  return useMutation(({id}: {id: number}) => client(`kanbans/${id}`, {method: 'DELETE'}), useDeleteConfig(queryKey))
}

export const useReorderKanban = (queryKey: QueryKey) => {
  const client = useHttp()
  return useMutation((params: SortProps) => {
    return client('kanbans/reorder', {
      data: params,
      method: 'POST'
    })
  }, useReorderTaskConfig(queryKey))
}