import { useCallback, useMemo } from 'react'
import { useLocation } from 'react-router'
import { useDebounce } from 'utils'
import { useKanbans } from 'utils/kanban'
import { useProject } from 'utils/project'
import { useTask, useTasks } from 'utils/task'
import { useUrlQueryParam } from 'utils/url'

export function useProjectIdInUrl() {
  const { pathname } = useLocation()
  const id = pathname.match(/projects\/(\d+)/)?.[1]
  return Number(id)
}

export const useProjectInUrl = () => useProject(useProjectIdInUrl())

export const useKanbanSearchParams = () => ({projectId: useProjectIdInUrl()})
export const useKanbansQueryKey = () => ['kanbans', useKanbanSearchParams()]

export const useTasksSearchParams = () => {
  const [params] = useUrlQueryParam(['name', 'typeId','processorId', 'tagId'])
  const projectId = useProjectIdInUrl()
  const debounceName = useDebounce(params.name, 200)
  return useMemo(() => ({
    projectId,
    typeId: Number(params.typeId) || undefined,
    tagId: Number(params.tagId) || undefined,
    processorId: Number(params.processorId) || undefined,
    name: debounceName
  }), [projectId, params, debounceName])
}
export const useTasksQueryKey = () => ['tasks', useTasksSearchParams()]

export const useTasksInProject = () => useTasks(useTasksSearchParams())
export const useKanbanInProject = () => useKanbans(useKanbanSearchParams())

export const useTasksModal = () => {
  const [{editingTaskId}, setEditingTaskId] = useUrlQueryParam(['editingTaskId'])
  const { data: editingTask, isLoading } = useTask(Number(editingTaskId))
  const startEdit = useCallback(
    (id: number) => {
      setEditingTaskId({editingTaskId: id})
    },
    [setEditingTaskId]
  )
  const close = useCallback(
    () => {
      setEditingTaskId({editingTaskId: undefined})
    },
    [setEditingTaskId],
  )
  return {
    editingTaskId,
    editingTask,
    isLoading,
    startEdit,
    close,
  }
}