import { Button, List, Modal, Spin } from 'antd'
import { Row, ScreenContainer } from 'components/lib'
import dayjs from 'dayjs'
import { useState } from 'react'
import { Link } from 'react-router-dom'
import { useProjectInUrl, useTasksInProject } from 'screens/kanban/util'
import { Epic } from 'types/epic'
import { useDeleteEpic, useEpics } from 'utils/epic'
import { CreateEpic } from './create-epic'
import { useEpicSearchParams, useEpicsQueryKey } from './util'

export const EpicScreen  = () =>{
  const {data: currentProject}  = useProjectInUrl()
  const {data: epics} = useEpics(useEpicSearchParams())
  const {data: tasks } = useTasksInProject()
  const { mutate: delEpic } = useDeleteEpic(useEpicsQueryKey())
  const [epicCreateOpen, setEpicCreateOpen] = useState(false)
  const onClose = () => setEpicCreateOpen(false)
  const onOpen  = ()  => setEpicCreateOpen(true)
  const confirmDelEpic = (epic: Epic) => () => 
     Modal.confirm({
      title: '删除任务',
      content:'是否确认删除当前任务',
      okText:'确认',
      cancelText:'取消',
      onOk(){
        delEpic({id: epic.id})
      }
    })
   
    if (!currentProject?.name) return <Spin size='large' />
    return <ScreenContainer>
    <Row between>
      <h1>{ currentProject?.name }任务组</h1>
      <Button type='link' onClick={onOpen}>创建任务组</Button>
    </Row>
    <List style={{overflowY: 'auto'}} dataSource={epics} itemLayout={'vertical'} renderItem={epic => <List.Item>
      <List.Item.Meta
        title={<Row between>
          <span>{epic.name}</span>
          <Button type='link' onClick={confirmDelEpic(epic)}>删除</Button>
        </Row>}
        description={<div>
          <div>开始时间: {dayjs(epic.start).format('YYYY-MM-DD HH:mm:ss')}</div>
          <div>结束时间:{dayjs(epic.end).format('YYYY-MM-DD HH:mm:ss')}</div>
        </div>}
      />
    <div>
      {
        tasks?.filter(task => task.epicId === epic.id).map(task => <Link key={task.id} to={`/projects/${currentProject?.id}/kanban?editingTaskId=${task.id}`} >{task.name}</Link>)
      }
    </div>
    </List.Item>} />
    <CreateEpic visible={epicCreateOpen} onClose={onClose} />
  </ScreenContainer>
}