import { Button, Form, Input, Modal } from "antd";
import { useForm } from "antd/lib/form/Form";
import { TaskTypeSelect } from "components/task-type-select";
import { UserSelect } from "components/user-select";
import { useEffect } from "react";
import { useDeleteTask, useEditTask } from "utils/task";
import { useTasksModal, useTasksQueryKey } from "./util";

const Layout = {
  labelCol: { span: 8 },
  wrapperCol: { span: 16 },
};

export const TaskModal = () => {
  const [form] = useForm();
  const { editingTaskId, close, editingTask } = useTasksModal();
  const { mutateAsync: deleteTask } = useDeleteTask(useTasksQueryKey())
  const { mutateAsync: editTask, isLoading: editLoading } = useEditTask(
    useTasksQueryKey()
  );
  const onCancel = () => {
    close();
    form.resetFields();
  };
  const onOk = async () => {
    await form.validateFields();
    await editTask({ ...editingTask, ...form.getFieldsValue() });
    close();
  };

  const startDel = () => {
    close()
    Modal.confirm({
      title: '删除任务',
      content: '是否确认删除当前任务',
      okText: '确认',
      cancelText: '取消',
      onOk () {
        deleteTask({id: Number(editingTaskId)})
      }
    })
  }

  useEffect(() => {
    form.setFieldsValue(editingTask);
  }, [form, editingTask]);
  return (
    <Modal
      forceRender
      onCancel={onCancel}
      onOk={onOk}
      okText="确认"
      cancelText="取消"
      confirmLoading={editLoading}
      title="编辑任务"
      visible={!!editingTaskId}
    >
      <Form initialValues={editingTask} form={form} {...Layout}>
        <Form.Item
          label="任务名"
          name="name"
          rules={[{ required: true, message: "请输入任务名" }]}
        >
          <Input allowClear />
        </Form.Item>
        <Form.Item label="经办人" name="processorId">
          <UserSelect defaultOptionName="经办人" />
        </Form.Item>
        <Form.Item label="任务类型" name="typeId">
          <TaskTypeSelect />
        </Form.Item>
      </Form>
      <div style={{textAlign: "right"}}>
          <Button onClick={startDel} style={{fontSize: '14px'}} size='small' danger>删除任务</Button>
      </div>
    </Modal>
  );
};
